import React, { Component } from "react";
import { FaTimes } from 'react-icons/fa'
import { FaSearchPlus, FaPlus, FaMinus } from 'react-icons/fa'

export class ShowFullItem extends Component {
  constructor(props) {
    super(props)
    this.state = { viewerOpen: false, viewerScale: 1 }
    this.openViewer = this.openViewer.bind(this)
    this.closeViewer = this.closeViewer.bind(this)
    this.onShowClose = this.onShowClose.bind(this)
    this.zoomIn = this.zoomIn.bind(this)
    this.zoomOut = this.zoomOut.bind(this)
  }

  openViewer(e) {
    e.stopPropagation()
    this.setState({ viewerOpen: true, viewerScale: 1 })
  }

  closeViewer(e) {
    if (e) e.stopPropagation()
    this.setState({ viewerOpen: false, viewerScale: 1 })
  }

  onShowClose(e) {
    e.stopPropagation()
    this.props.onShowItem(this.props.item)
  }

  zoomIn(e) {
    e.stopPropagation()
    this.setState(({ viewerScale }) => ({ viewerScale: Math.min(3, viewerScale + 0.25) }))
  }

  zoomOut(e) {
    e.stopPropagation()
    this.setState(({ viewerScale }) => ({ viewerScale: Math.max(0.5, viewerScale - 0.25) }))
  }

  render() {
    const { item } = this.props
    return (
      <div className="full-item" onClick={this.onShowClose}>
        <div onClick={(e) => e.stopPropagation()}>
          <button className="close-full" onClick={this.onShowClose}><FaTimes/></button>
          <img
            src={"./img/" + item.img}
            alt="staff"
          />
          <h2>{item.title}</h2>
          <p>{item.desc}</p>
          <b>{item.price}$</b>
          <div
            className="add-to-cart"
            onClick={() => this.props.onAdd(item)}
          >
            +
          </div>
          <button className="view-image" onClick={this.openViewer}><FaSearchPlus/></button>
        </div>

        {this.state.viewerOpen && (
          <div className="photo-viewer" onClick={this.closeViewer}>
            <div className="photo-viewer-inner" onClick={(e) => e.stopPropagation()}>
              <button className="pv-close" onClick={this.closeViewer}><FaTimes/></button>
              <div className="pv-img-wrap">
                <img src={"./img/" + item.img} alt={item.title} style={{transform: `scale(${this.state.viewerScale})`}} />
              </div>
              <div className="pv-controls">
                <button className="pv-btn" onClick={this.zoomOut}><FaMinus/></button>
                <button className="pv-btn" onClick={this.zoomIn}><FaPlus/></button>
              </div>
            </div>
          </div>
        )}
      </div>
    );
  }
}

export default ShowFullItem;
